'use strict';
// KOP embedded base64
const KOP_BASE64 = '';
const { chromium } = require('playwright');
const readline = require('readline');

function ask(rl, q) { return new Promise(r => rl.question(q, r)); }

function kv(key, val) {
  return `<div style="display:flex;margin-bottom:3px;font-size:12pt">
    <span style="min-width:190px;padding-left:40px">${key}</span>
    <span style="min-width:16px">:</span>
    <span>${val}</span></div>`;
}

function tbl(headers, rows) {
  const th = headers.map(h=>`<th style="border:1px solid #000;padding:5px 8px;font-weight:bold;text-align:center;background:#fff">${h}</th>`).join('');
  const tr = rows.map(r=>'<tr>'+r.map(c=>`<td style="border:1px solid #000;padding:5px 8px;vertical-align:top">${c}</td>`).join('')+'</tr>').join('');
  return `<table style="width:100%;border-collapse:collapse;margin:12px 0;font-size:11pt"><thead><tr>${th}</tr></thead><tbody>${tr}</tbody></table>`;
}

function ttd1(tanggal, nama, jabatan, inst='PT Nusa Inspira Teknologi') {
  return `<div style="margin-top:32px"><p>${tanggal}</p><br><br><br><br>
    <p style="font-weight:bold">(${nama})</p><p>${jabatan}</p><p>${inst}</p></div>`;
}

function ttd2(tanggal, lLbl, lNama, lJab, rLbl, rNama, rJab, inst='PT Nusa Inspira Teknologi') {
  return `<div style="margin-top:32px"><p>${tanggal}</p>
    <div style="display:flex;justify-content:space-between;margin-top:8px">
      <div style="text-align:center;min-width:200px"><p>${lLbl}</p><br><br><br><br>
        <p style="font-weight:bold">(${lNama})</p><p>${lJab}</p><p>${inst}</p></div>
      <div style="text-align:center;min-width:200px"><p>${rLbl}</p><br><br><br><br>
        <p style="font-weight:bold">(${rNama})</p><p>${rJab}</p><p>${inst}</p></div>
    </div></div>`;
}

function page(body) {
  return `<!DOCTYPE html><html lang="id"><head><meta charset="UTF-8">
  <style>
    *{margin:0;padding:0;box-sizing:border-box}
    body{font-family:'Times New Roman',serif;font-size:12pt;color:#000;background:#fff}
    .title{text-align:center;font-weight:bold;text-decoration:underline;font-size:13pt;margin:14px 0 4px}
    .nomor{text-align:center;margin-bottom:18px}
    .para{margin-bottom:10px;text-align:justify}
    .kls{text-align:center;font-weight:bold;border:2px solid #000;padding:4px;margin:8px 0 14px;letter-spacing:2px}
    .fl{border-top:1px solid #000;margin:16px 0 6px}
  </style></head><body>
  <img style="width:100%;display:block" src="data:image/png;base64,${KOP_BASE64}" alt="KOP">
  <div style="padding:16px 56px 48px 56px;line-height:1.6">${body}</div>
  </body></html>`;
}

async function generatePDF(html, out) {
  const browser = await chromium.launch();
  const pg = await browser.newPage();
  await pg.setContent(html, {waitUntil:'networkidle'});
  await pg.pdf({path:out, width:'794px', height:'1123px', printBackground:true,
    margin:{top:'0',right:'0',bottom:'0',left:'0'}});
  await browser.close();
  console.log('\n✅ PDF berhasil dibuat:', out);
}


async function collectData(rl) {
  console.log('\n=== MOU ===\n');
  return {
    nomor:   await ask(rl,'Nomor Surat          : '),
    p1_nm:   await ask(rl,'Pihak 1 - Nama       : '),
    p1_jab:  await ask(rl,'Pihak 1 - Jabatan    : '),
    p1_ins:  await ask(rl,'Pihak 1 - Instansi   : '),
    p2_nm:   await ask(rl,'Pihak 2 - Nama       : '),
    p2_jab:  await ask(rl,'Pihak 2 - Jabatan    : '),
    p2_ins:  await ask(rl,'Pihak 2 - Instansi   : '),
    lingkup: await ask(rl,'Ruang Lingkup        : '),
    jangka:  await ask(rl,'Jangka Waktu         : '),
    kerah:   await ask(rl,'Ketentuan Kerahasiaan: '),
    tgl:     await ask(rl,'Tanggal Surat        : '),
    out:     await ask(rl,'Nama file PDF        : ') || 'mou.pdf',
  };
}
function buildBody(d) {
  return `<p class="title">MEMORANDUM OF UNDERSTANDING (MOU)</p>
    <p class="nomor">Nomor: ${d.nomor}</p>
    <p class="para">MOU ini dibuat dan ditandatangani pada ${d.tgl}, di Jakarta, oleh dan antara:</p>
    <p><strong>1. ${d.p1_ins.toUpperCase()}</strong></p>
    <p class="para" style="margin-left:20px">Diwakili oleh <strong>${d.p1_nm}</strong> selaku ${d.p1_jab}, selanjutnya disebut <strong>PIHAK PERTAMA</strong>.</p>
    <p><strong>2. ${d.p2_ins.toUpperCase()}</strong></p>
    <p class="para" style="margin-left:20px">Diwakili oleh <strong>${d.p2_nm}</strong> selaku ${d.p2_jab}, selanjutnya disebut <strong>PIHAK KEDUA</strong>.</p>
    <p><strong>Pasal 1 — Ruang Lingkup</strong></p><p class="para">${d.lingkup}</p>
    <p><strong>Pasal 2 — Jangka Waktu</strong></p>
    <p class="para">MOU ini berlaku selama ${d.jangka} sejak ditandatangani dan dapat diperpanjang atas kesepakatan Para Pihak.</p>
    <p><strong>Pasal 3 — Kerahasiaan</strong></p><p class="para">${d.kerah}</p>
    <p><strong>Pasal 4 — Penutup</strong></p>
    <p class="para">MOU ini dibuat dalam 2 (dua) rangkap asli, bermaterai cukup, masing-masing mempunyai kekuatan hukum yang sama.</p>
    ${ttd2(d.tgl,'PIHAK PERTAMA',d.p1_nm,d.p1_jab,'PIHAK KEDUA',d.p2_nm,d.p2_jab)}`;
}

(async () => {
  const rl = readline.createInterface({input:process.stdin,output:process.stdout});
  try {
    const d = await collectData(rl);
    rl.close();
    await generatePDF(page(buildBody(d)), d.out || 'output.pdf');
  } catch(e) { console.error('Error:', e.message); process.exit(1); }
})();
